import UIKit
import SwiftUI

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let rootViewController = MainViewController()
        let navigationController = UINavigationController(rootViewController: rootViewController)
        window.rootViewController = navigationController
        self.window = window
        window.makeKeyAndVisible()
        
        if let userActivity = connectionOptions.userActivities.first {
            handleUniversalLink(userActivity: userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUniversalLink(userActivity: userActivity)
    }
    
    private func handleUniversalLink(userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return
        }
        
        UniversalLinkHandler.shared.handle(url: incomingURL)
    }
}

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handle(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return
        }
        
        guard let path = components.path.isEmpty ? nil : components.path else {
            return
        }
        
        if path == "/reset-password" || path == "/reset-password/" {
            handlePasswordReset(queryItems: components.queryItems)
        }
    }
    
    private func handlePasswordReset(queryItems: [URLQueryItem]?) {
        guard let token = queryItems?.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            showError(message: "Invalid or missing reset token")
            return
        }
        
        navigateToPasswordReset(token: token)
    }
    
    private func navigateToPasswordReset(token: String) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let navigationController = window.rootViewController as? UINavigationController else {
                return
            }
            
            let passwordResetVC = PasswordResetViewController(token: token)
            navigationController.pushViewController(passwordResetVC, animated: true)
        }
    }
    
    private func showError(message: String) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                return
            }
            
            let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            rootViewController.present(alert, animated: true)
        }
    }
}

