class PasswordResetService {
    static let shared = PasswordResetService()
    
    private init() {}
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, Error>) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 2.0) {
            if self.validateToken(token) {
                completion(.success(()))
            } else {
                completion(.failure(PasswordResetError.invalidToken))
            }
        }
    }
    
    private func validateToken(_ token: String) -> Bool {
        return !token.isEmpty && token.count > 5
    }
}

enum PasswordResetError: LocalizedError {
    case invalidToken
    case networkError
    case serverError
    
    var errorDescription: String? {
        switch self {
        case .invalidToken:
            return "The reset token is invalid or has expired"
        case .networkError:
            return "Network connection error"
        case .serverError:
            return "Server error occurred"
        }
    }
}